+/// Format timestamp as ISO8601 (Ollama format: "2023-08-04T19:22:45.499127Z")
+fn formatISO8601(buf: []u8) []const u8 {
+    const ts = std.time.timestamp();
+    const epoch_secs: u64 = @intCast(ts);
+    const epoch = std.time.epoch.EpochSeconds{ .secs = epoch_secs };
+    const day = epoch.getEpochDay();
+    const year_day = day.calculateYearDay();
+    const month_day = year_day.calculateMonthDay();
+    const day_secs = epoch.getDaySeconds();
+
+    const len = std.fmt.bufPrint(buf, "{d:0>4}-{d:0>2}-{d:0>2}T{d:0>2}:{d:0>2}:{d:0>2}.000000Z", .{
+        year_day.year,
+        month_day.month.numeric(),
+        month_day.day_index + 1,
+        day_secs.getHoursIntoDay(),
+        day_secs.getMinutesIntoHour(),
+        day_secs.getSecondsIntoMinute(),
+    }) catch return "1970-01-01T00:00:00.000000Z";
+    return buf[0..len.len];
+}
