+    /// POST /api/generate - Ollama text completion
+    fn handleOllamaGenerate(self: *Self, stream: std.net.Stream, method: []const u8, body: []const u8) !void {
+        if (!std.mem.eql(u8, method, "POST")) {
+            try self.sendError(stream, 405, "Method not allowed");
+            stream.close();
+            return;
+        }
+
+        // Parse Ollama generate request
+        const parsed = std.json.parseFromSlice(OllamaGenerateRequest, self.allocator, body, .{
+            .ignore_unknown_fields = true,
+        }) catch {
+            try self.sendError(stream, 400, "Invalid JSON");
+            stream.close();
+            return;
+        };
+        defer parsed.deinit();
+
+        const gen_req = parsed.value;
+        const stream_mode = gen_req.stream orelse true; // Ollama defaults to streaming
+
+        // Build prompt (with optional system)
+        var prompt_builder: std.ArrayListUnmanaged(u8) = .{};
+        errdefer prompt_builder.deinit(self.allocator);
+
+        var system_prompt_len: u32 = 0;
+
+        if (gen_req.system) |sys| {
+            try prompt_builder.appendSlice(self.allocator, "<|im_start|>system\n");
+            try prompt_builder.appendSlice(self.allocator, sys);
+            try prompt_builder.appendSlice(self.allocator, "<|im_end|>\n");
+            system_prompt_len = @intCast(prompt_builder.items.len);
+        }
