+        try prompt_builder.appendSlice(self.allocator, gen_req.prompt);
+        try prompt_builder.appendSlice(self.allocator, "<|im_end|>\n");
+        try prompt_builder.appendSlice(self.allocator, "<|im_start|>assistant\n");
+
+        const max_tokens = if (gen_req.options) |opts| opts.num_predict orelse 256 else 256;
+
+        // Check queue capacity
